script:
frappe.ui.form.on('Asset', {

    custom__last_maintenance_date: function(frm) {
        calculate_next_date(frm);
    },

    custom_maintenance_interval: function(frm) {
        calculate_next_date(frm);
    },

    custom_maintenance_frequency_type: function(frm) {
        calculate_next_date(frm);
    }

});

function calculate_next_date(frm) {

    if (!frm.doc.custom__last_maintenance_date || 
        !frm.doc.custom_maintenance_interval || 
        !frm.doc.custom_maintenance_frequency_type) {
        return;
    }

    let last_date = frappe.datetime.str_to_obj(frm.doc.custom__last_maintenance_date);
    let interval = parseInt(frm.doc.custom_maintenance_interval);
    let frequency = frm.doc.custom_maintenance_frequency_type;

    if (frequency === "Daily") {
        last_date.setDate(last_date.getDate() + interval);
    }

    if (frequency === "Weekly") {
        last_date.setDate(last_date.getDate() + (7 * interval));
    }

    if (frequency === "Monthly") {
        last_date.setMonth(last_date.getMonth() + interval);
    }

    if (frequency === "Yearly") {
        last_date.setFullYear(last_date.getFullYear() + interval);
    }

    frm.set_value("custom__next_maintenance_date",
        frappe.datetime.obj_to_str(last_date)
    );
}

frappe.ui.form.on('Asset', {

    custom_asset_category_custom: function(frm) {

        if (frm.doc.custom_asset_category_custom) {

            frm.set_value('item_code', frm.doc.custom_asset_category_custom);

        }

    }

});

frappe.ui.form.on('Asset', {

    // Setup stage
    setup: function(frm) {
        frm.set_query('asset_name', function() {
            return {
                filters: {
                    asset_category_name: frm.doc.custom_category
                }
            };
        });
    },

    // When category changes
    custom_category: function(frm) {
        frm.set_value('asset_name', null);
        frm.set_value('custom_asset_number', null);
    },

    // When name is selected
    asset_name: function(frm) {
        if (frm.doc.asset_name) {
            frm.set_value('custom_asset_number', frm.doc.asset_name);
        } else {
            frm.set_value('custom_asset_number', null);
        }
    }

});
